{"method_body":"{
  sum := 0;
  var i := a;

  while i <= b
    invariant sum + sum_odd(i, b) == sum_odd(a, b)
    decreases b - i + 1
  {
    if i % 2 == 1 {
      assert sum_odd(i, b) == i + sum_odd(i + 1, b);
      sum := sum + i;
    } else {
      assert sum_odd(i, b) == sum_odd(i + 1, b);
    }
    i := i + 1;
  }

  assert i > b;
  assert sum_odd(i, b) == 0;
}"}

